-- Fix session data structure for Symphony trainings (IDs 11, 12, 14, 16, 20)
-- Ensure story.part1/part2 are arrays, quickCheck has correct structure

-- Training 11: Symphonyシリーズ全体像
UPDATE session_contents
SET 
  story = '{"part1": [{"title": "ある日の営業シーン", "content": "田中さんは中古車販売店「カーライフ山田」を訪問しました。\n\n店長の山田さん：「最近、業務が回らなくて困っているんだよね。在庫管理、広告掲載、顧客管理...全部バラバラのシステムで、二度手間三度手間だよ。」\n\n田中さん：「山田さん、そのお悩み、よく分かります。実は今日ご紹介したいのが、まさにその課題を解決するSymphonyシリーズなんです。」"}], "part2": [{"title": "Symphonyの価値を伝える", "content": "田中さん：「Symphonyシリーズは『分かりやすい』『つながる』『売上が伸びる』の3つの価値を提供します。\n\n一度入力すれば、在庫管理から広告掲載、顧客管理まで全てが連携します。」\n\n山田さん：「へぇ、それは便利そうだね。具体的にはどんな製品があるの？」\n\n田中さん：「販売管理を中心に、整備請求、ワンプラという在庫共有サービスがあります。お店の課題に合わせて組み合わせられるんです。」"}]}',
  quick_check = '[{"question": "Symphonyシリーズの3つの価値は？", "options": ["安い・早い・うまい", "分かりやすい・つながる・売上が伸びる", "品質・価格・サービス", "信頼・実績・サポート"], "correctIndex": 1, "explanation": "Symphonyは「分かりやすい」「つながる」「売上が伸びる」の3つの価値を提供します。"}]',
  simulation = '{"scenario": "顧客の課題に応じた製品提案", "customerProfile": "在庫30台の中古車販売店。オーナー1人で運営。手書き管理に限界を感じている。", "options": [{"text": "Symphony販売管理を提案", "isCorrect": true, "feedback": "正解です！まずは販売管理で業務効率化を実現し、成功体験を作りましょう。"}, {"text": "全製品をセットで提案", "isCorrect": false, "feedback": "いきなり全製品は負担が大きいです。まずは核となる販売管理から始めましょう。"}, {"text": "ワンプラだけを提案", "isCorrect": false, "feedback": "ワンプラは仕入れ・業販に特化しています。業務管理の課題には販売管理が適切です。"}]}'
WHERE training_id = 11;

-- Training 12: Symphony販売管理
UPDATE session_contents
SET 
  story = '{"part1": [{"title": "販売管理の価値を伝える", "content": "山田さん：「販売管理って具体的に何ができるの？」\n\n田中さん：「一言で言うと『一度の入力で、すべて完結』です。\n\n車両情報を登録すれば、カーセンサー、グーネット、Yahoo!オークションなど10以上のメディアに一括掲載できます。」\n\n山田さん：「え、今は各サイトに別々に入力してるよ...それだけで1日2時間はかかってる。」"}], "part2": [{"title": "競合優位性を説明", "content": "田中さん：「他社システムとの違いは、Symphonyシリーズ全体との連携です。\n\n販売管理で登録した車両は、ワンプラで業販出品もできます。整備請求と連携すれば、販売した顧客の車検時期も自動でフォローできます。」\n\n山田さん：「なるほど、単体じゃなくて、全体で価値が出るってことか。」\n\n田中さん：「その通りです！1+1を3にする。それがSymphony連携の価値です。」"}]}',
  quick_check = '[{"question": "Symphony販売管理で一括掲載できるメディア数は？", "options": ["3サイト以上", "5サイト以上", "10サイト以上", "20サイト以上"], "correctIndex": 2, "explanation": "カーセンサー、グーネット、Yahoo!オークションなど10以上のメディアに一括掲載できます。"}]',
  simulation = '{"scenario": "販売管理の導入効果を説明", "customerProfile": "1日2時間を広告掲載作業に費やしている店舗オーナー", "options": [{"text": "「入力作業が約50%削減できます」と数字で伝える", "isCorrect": true, "feedback": "正解！具体的な数字で効果を伝えることで説得力が増します。"}, {"text": "「便利になります」と抽象的に伝える", "isCorrect": false, "feedback": "抽象的な表現より、具体的な数字で伝えましょう。"}, {"text": "「他社より安いです」と価格を強調", "isCorrect": false, "feedback": "価格より先に、課題解決の価値を伝えましょう。"}]}'
WHERE training_id = 12;

-- Training 14: シンフォニーワンプラ
UPDATE session_contents
SET 
  story = '{"part1": [{"title": "仕入れの課題", "content": "山田さん：「最近、オークションだけじゃ欲しい車が見つからなくてね。」\n\n田中さん：「そのお悩み、シンフォニーワンプラで解決できます。\n\n全国の中古車販売店をつなぐ在庫共有プラットフォームで、7万台の共有在庫から24時間いつでも仕入れができます。」\n\n山田さん：「7万台！それはすごいね。手数料は高いの？」"}], "part2": [{"title": "手数料体系の説明", "content": "田中さん：「ワンプラの手数料は業界最安水準です。\n\n出品成約料と落札料の2種類があり、成約時のみ発生します。固定費はゼロなので、リスクなく始められます。」\n\n山田さん：「固定費ゼロは嬉しいね。売れない在庫の処分にも使える？」\n\n田中さん：「はい！仕入れだけでなく、長期在庫を全国の業者に業販出品することもできます。在庫回転率アップに貢献します。」"}]}',
  quick_check = '[{"question": "シンフォニーワンプラの手数料体系は？", "options": ["月額固定費のみ", "出品成約料と落札料（成約時のみ）", "年会費制", "売上の一定割合"], "correctIndex": 1, "explanation": "ワンプラは出品成約料と落札料の2種類で、成約時のみ発生。固定費はゼロです。"}]',
  simulation = '{"scenario": "ワンプラの2つの使い方を提案", "customerProfile": "仕入れルートを増やしたい、長期在庫も処分したい店舗", "options": [{"text": "「仕入れと業販出品、両方できます」と提案", "isCorrect": true, "feedback": "正解！ワンプラは仕入れにも在庫処分にも使える一石二鳥のサービスです。"}, {"text": "「仕入れ専用のサービスです」と説明", "isCorrect": false, "feedback": "ワンプラは仕入れだけでなく、業販出品もできます。"}, {"text": "「オークションの代わりです」と説明", "isCorrect": false, "feedback": "ワンプラはオークションを「補完」するサービスで、代替ではありません。"}]}'
WHERE training_id = 14;

-- Training 16: 製品間連携の価値
UPDATE session_contents
SET 
  story = '{"part1": [{"title": "連携の価値を実感", "content": "3ヶ月後、山田さんの店舗を再訪問。\n\n山田さん：「田中さん、販売管理を導入してから本当に楽になったよ！」\n\n田中さん：「それは良かったです！実は今日は、さらに効果を高める提案があるんです。」\n\n山田さん：「ほう、何だい？」\n\n田中さん：「ワンプラとの連携です。販売管理の在庫データを自動でワンプラに出品できるので、業販の手間がゼロになります。」"}], "part2": [{"title": "クロスセルの成功", "content": "山田さん：「自動連携か...確かに今は手動で出品してるから面倒だったんだよね。」\n\n田中さん：「さらに、整備請求を追加すれば、販売した顧客の車検時期を自動フォローできます。リピート率が15%向上した店舗もあります。」\n\n山田さん：「車検の案内、今は手書きでやってるよ...全部連携したら、どれくらい効率上がるかな？」\n\n田中さん：「ROI試算をしてみましょう！」"}]}',
  quick_check = '[{"question": "製品連携の効果として正しいものは？", "options": ["価格が安くなる", "データの自動連携で二重入力が不要になる", "サポートが手厚くなる", "機能が減る"], "correctIndex": 1, "explanation": "製品連携により、データが自動連携され、二重入力が不要になります。"}]',
  simulation = '{"scenario": "クロスセルのタイミング判断", "customerProfile": "販売管理を3ヶ月利用し、効果を実感している店舗", "options": [{"text": "成功体験を確認してから次の製品を提案", "isCorrect": true, "feedback": "正解！現製品で成功を実感してから、次の課題解決を提案するのが効果的です。"}, {"text": "導入初日に全製品を提案", "isCorrect": false, "feedback": "まずは1つの製品で成功体験を作ることが重要です。"}, {"text": "顧客から連絡があるまで待つ", "isCorrect": false, "feedback": "能動的にフォローし、タイミングを見て提案しましょう。"}]}'
WHERE training_id = 16;

-- Training 20: ROI計算の実践
UPDATE session_contents
SET 
  story = '{"part1": [{"title": "ROIの重要性", "content": "田中さんは新人の佐藤さんに教えています。\n\n田中さん：「佐藤さん、ROI計算はできる？」\n\n佐藤さん：「ROI...投資対効果ですよね。なんとなくは分かりますが...」\n\n田中さん：「『いくら儲かるのか』『いつ回収できるのか』を具体的な数字で示せると、お客様の意思決定を後押しできるんだ。」"}], "part2": [{"title": "ROI計算の実践", "content": "田中さん：「例えば、在庫30台の店舗で、入力作業に1日2時間かかっているとする。\n\nSymphony導入で50%削減できれば、月20時間の削減。時給1,500円で計算すると月3万円の効果だね。」\n\n佐藤さん：「なるほど、時間を金額に換算するんですね！」\n\n田中さん：「そう。さらに在庫回転率向上による売上増も加えると、数ヶ月で投資回収できることが多いよ。」"}]}',
  quick_check = '[{"question": "ROI計算で効果を算出する主な項目は？", "options": ["競合の価格", "時間削減・売上増加・コスト削減", "従業員の満足度", "会社の知名度"], "correctIndex": 1, "explanation": "ROI計算では、時間削減効果、売上増加効果、コスト削減効果を金額換算します。"}]',
  simulation = '{"scenario": "顧客へのROI説明", "customerProfile": "導入コストを気にしている見込み客", "options": [{"text": "「ROI試算では○ヶ月で回収できます」と具体的に説明", "isCorrect": true, "feedback": "正解！具体的な数字でROIを示すことで、投資判断を後押しできます。"}, {"text": "「きっと元が取れますよ」と曖昧に説明", "isCorrect": false, "feedback": "曖昧な説明より、具体的な数字で示しましょう。"}, {"text": "「コストの話は後で」と避ける", "isCorrect": false, "feedback": "コストへの懸念には正面から向き合い、ROIで説明しましょう。"}]}'
WHERE training_id = 20;
